#include <bits/stdc++.h>
using namespace std;
const int maxn=3e6+5;
int son[maxn][65];
int cnt[maxn],val[maxn],idx;
int get_id(char c) {
	if(c>='a'&&c<='z') {
		return c-'a';
	} else if(c>='A'&&c<='Z') {
		return c-'A'+26;
	} else {
		return c-'0'+52;
	}
}
void insert(string &s) {
	int p=0;
	for(auto c:s) {
		int u=get_id(c);
		if(!son[p][u]) {
			son[p][u]=++idx;
		}
		cnt[son[p][u]]++;
		p=son[p][u];
	}
	val[p]++;
}
//query1查找前缀 
int query1(string &s) {
	int p=0;
	for(auto c:s) {
		int u=get_id(c);
		if(!son[p][u]) {
			return 0;
		}
		p=son[p][u];
	}
	return cnt[p];
}
//query2查找全词 
int query2(string &s) {
	int p=0;
	for(auto c:s) {
		int u=get_id(c);
		if(!son[p][u]) {
			return 0;
		}
		p=son[p][u];
	}
	return val[p];
}
void clear() {
	for(int i=0; i<=idx; i++) {
		for(int j=0; j<65; j++) {
			son[i][j]=0;
		}
		cnt[i]=0;
		val[i]=0;
	}
	idx=0;
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	int t;
	cin>>t;
	while(t--) {
		clear();
		int n,q;
		cin>>n>>q;
		for(int i=1; i<=n; i++) {
			string s;
			cin>>s;
			insert(s);
		}
		for(int i=1;i<=q;i++){
			string s;
			cin>>s;
			cout<<query1(s)<<"\n";
		}
	}
	return 0;
}
